1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums for single items
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("quote for a single plain sword yields 105 G (100 base + 5 fee)");
14	  it.todo("quote for a single plain amulet yields 65 G (60 base + 5 fee)");
15	  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
16	  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");
17	
18	  // Quote — components and building block
19	  it.todo("quote for a single rune yields 30 G (25 base + 5 fee)");
20	  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee, no block)");
21	  it.todo("quote for 3 runes yields 65 G (60 block base + 5 fee)");
22	  it.todo("quote for 4 runes yields 105 G (100 base + 5 fee, no block)");
23	  it.todo("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, different types)");
24	  it.todo("quote for 3 runes + 3 moonstones yields 125 G (two blocks of 60 + 5 fee)");
25	
26	  // Quote — premium modifiers (item-specific)
27	  it.todo("cursed sword adds 50% surcharge on that item's base premium");
28	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge on its base premium");
29	  it.todo("sword with enchantment exactly 5 triggers high-enchantment surcharge");
30	  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
31	  it.todo("cursed and highly enchanted item gets both surcharges");
32	
33	  // Quote — premium modifiers (policy-wide)
34	  it.todo("long-standing customer (≥ 2 years) receives 20% loyalty discount on policy base premium");
35	  it.todo("customer with exactly 2 years gets loyalty discount");
36	  it.todo("first insurance adds 10% surcharge per item");
37	  it.todo("follow-up contract (after first) gets 15% discount on policy base premium");
38	
39	  // Quote — rounding
40	  it.todo("premium rounds up to whole G in MHPCO's favor");
41	
42	  // Integration — newcomer with cursed sword: 165 G
43	  it.todo("newcomer with cursed sword yields 165 G");
44	
45	  // Integration — long-standing customer's second contract: 160 G
46	  it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");
47	
48	  // Claim — basic
49	  it.todo("standard sword claim of 500 G yields payout 400 G (full minus 100 deductible)");
50	  it.todo("rune damage of 200 G yields payout 100 G (full minus 100 deductible)");
51	  it.todo("payout rounds down in MHPCO's favor");
52	
53	  // Claim — special clauses
54	  it.todo("high enchantment (≥ 8) reimburses 50% of damage, then deductible");
55	  it.todo("dragon material item is fully reimbursed");
56	  it.todo("dragon material with high enchantment: 50% rule wins, then deductible");
57	
58	  // Claim — multiple damages
59	  it.todo("multiple damages each get their own deductible");
60	
61	  // Claim — cap
62	  it.todo("payout capped at twice the insurance sum");
63	  it.todo("successive claims exhaust remaining cap");
64	
65	  // Multi-item policy
66	  it.todo("policy with cursed sword and plain amulet yields 215 G");
67	  it.todo("policy with two swords has insurance sum 2000 G, cap 4000 G");
68	
69	  // Errors
70	  it.todo("unknown item type causes CLI to exit non-zero");
71	  it.todo("claim with item not in policy causes non-zero exit");
72	  it.todo("claim with negative damage amount causes non-zero exit");
73	  it.todo("more damage entries of a type than insured items causes non-zero exit");
74	});
